namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = new();
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _categoryNames;
    private readonly EvaluationResponse _evaluationMetrics;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Combine text features and build the pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered category names from the label key mapping
        var labelColumn = dataView.Schema["Category"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Label"]
            .GetKeyValues(ref slotNames);
        _categoryNames = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();

        // Evaluate with cross-validation on the small dataset
        _evaluationMetrics = Evaluate(dataView, pipeline);
    }

    public (string Category, Dictionary<string, float> Confidence) Predict(TicketRequest request)
    {
        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _categoryNames.Length; i++)
        {
            confidence[_categoryNames[i]] = prediction.Score[i];
        }

        return (prediction.Category, confidence);
    }

    public EvaluationResponse GetMetrics() => _evaluationMetrics;

    private EvaluationResponse Evaluate(IDataView dataView,
        IEstimator<ITransformer> pipeline)
    {
        // Cross-validate to get reliable metrics on the small dataset
        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        var best = cvResults
            .OrderByDescending(r => r.Metrics.MacroAccuracy)
            .First().Metrics;

        // Also evaluate the final model on training data for per-category metrics
        var predictions = _model.Transform(dataView);
        var fullMetrics = _mlContext.MulticlassClassification
            .Evaluate(predictions, labelColumnName: "Label");

        var perCategory = new List<CategoryMetric>();
        if (fullMetrics.PerClassLogLoss.Count > 0)
        {
            for (int i = 0; i < _categoryNames.Length; i++)
            {
                var confusionMatrix = fullMetrics.ConfusionMatrix;
                var counts = confusionMatrix.Counts;

                double tp = i < counts.Count && i < counts[i].Count ? counts[i][i] : 0;

                double colSum = 0;
                for (int row = 0; row < counts.Count; row++)
                    if (i < counts[row].Count)
                        colSum += counts[row][i];

                double rowSum = i < counts.Count
                    ? counts[i].Sum()
                    : 0;

                double precision = colSum > 0 ? tp / colSum : 0;
                double recall = rowSum > 0 ? tp / rowSum : 0;
                double f1 = (precision + recall) > 0
                    ? 2 * precision * recall / (precision + recall) : 0;

                perCategory.Add(new CategoryMetric
                {
                    Category = _categoryNames[i],
                    Precision = Math.Round(precision, 4),
                    Recall = Math.Round(recall, 4),
                    F1Score = Math.Round(f1, 4)
                });
            }
        }

        return new EvaluationResponse
        {
            MicroAccuracy = (float)Math.Round(best.MicroAccuracy, 4),
            MacroAccuracy = (float)Math.Round(best.MacroAccuracy, 4),
            LogLoss = (float)Math.Round(best.LogLoss, 4),
            LogLossReduction = (float)Math.Round(best.LogLossReduction, 4),
            PerCategoryMetrics = perCategory
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority < 1 || request.Priority > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var (category, confidence) = _classifier.Predict(request);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = category,
            Confidence = confidence
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

